#include <omp.h>

#include <chrono>
#include <cstddef>
#include <cstdint>
#include <cstdio>
#include <cstring>

#include "mix_kernels_cpu.h"

#define ELEMENTS_PER_THREAD (8)
#define FUSION_DEGREE (4)

struct half2 {
  float x;
  float y;
};

template <class T>
inline T conv_int(const int i) {
  return static_cast<T>(i);
}

template <>
inline half2 conv_int<half2>(const int i) {
  const float v = static_cast<float>(i);
  return half2{v, v};
}

template <class T>
inline T mad(const T a, const T b, const T c) {
  return a * b + c;
}

template <>
inline half2 mad<half2>(const half2 a, const half2 b, const half2 c) {
  return half2{a.x * b.x + c.x, a.y * b.y + c.y};
}

template <class T>
inline bool equal(const T a, const T b) {
  return a == b;
}

template <>
inline bool equal<half2>(const half2 a, const half2 b) {
  return a.x == b.x && a.y == b.y;
}

template <class T, int blockdim, unsigned int granularity,
          unsigned int fusion_degree, unsigned int compute_iterations,
          bool TemperateUnroll>
static void benchmark_func_cpu(T seed, T* g_data, int total_blocks) {
  (void)TemperateUnroll;
  const unsigned int blockSize = blockdim;
  const int stride = static_cast<int>(blockSize);
  const int big_stride = total_blocks * static_cast<int>(blockSize) *
                         static_cast<int>(granularity);
  const int total_threads = total_blocks * static_cast<int>(blockSize);

#pragma omp parallel for schedule(static)
  for (int t = 0; t < total_threads; t++) {
    const int block = t / static_cast<int>(blockSize);
    const int thread = t % static_cast<int>(blockSize);
    const int idx = block * static_cast<int>(blockSize) *
                        static_cast<int>(granularity) +
                    thread;

    T tmps[granularity];
    for (unsigned int k = 0; k < fusion_degree; k++) {
      for (unsigned int j = 0; j < granularity; j++) {
        tmps[j] = g_data[idx + static_cast<int>(j) * stride +
                         static_cast<int>(k) * big_stride];

        for (unsigned int i = 0; i < compute_iterations; i++) {
          tmps[j] = mad(tmps[j], tmps[j], seed);
        }
      }

      T sum = conv_int<T>(0);
      for (unsigned int j = 0; j < granularity; j += 2) {
        sum = mad(tmps[j], tmps[j + 1], sum);
      }

      if (equal(sum, conv_int<T>(-1))) {
        g_data[idx + static_cast<int>(k) * big_stride] = sum;
      }
    }
  }
}

static void runbench_warmup(double* cd, long size) {
  const long reduced_grid_size = size / (ELEMENTS_PER_THREAD) / 128;
  const int BLOCK_SIZE = 256;
  const int TOTAL_REDUCED_BLOCKS =
      static_cast<int>(reduced_grid_size / BLOCK_SIZE);

  benchmark_func_cpu<short, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE, 0,
                     true>((short)1, reinterpret_cast<short*>(cd),
                           TOTAL_REDUCED_BLOCKS);
}

template <unsigned int compute_iterations>
static void runbench(double* cd, long size, bool doHalfs) {
  const long compute_grid_size = size / ELEMENTS_PER_THREAD / FUSION_DEGREE;
  const int BLOCK_SIZE = 256;
  const int TOTAL_BLOCKS = static_cast<int>(compute_grid_size / BLOCK_SIZE);
  const long long computations =
      (ELEMENTS_PER_THREAD * (long long)compute_grid_size +
       (2 * ELEMENTS_PER_THREAD * compute_iterations) *
           (long long)compute_grid_size) *
      FUSION_DEGREE;
  const long long memoryoperations = size;

  auto t0 = std::chrono::high_resolution_clock::now();
  benchmark_func_cpu<float, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE,
                     compute_iterations, false>(1.0f,
                                                reinterpret_cast<float*>(cd),
                                                TOTAL_BLOCKS);
  auto t1 = std::chrono::high_resolution_clock::now();
  float kernel_time_mad_sp =
      std::chrono::duration<float, std::milli>(t1 - t0).count();

  t0 = std::chrono::high_resolution_clock::now();
  benchmark_func_cpu<double, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE,
                     compute_iterations, false>(1.0, cd, TOTAL_BLOCKS);
  t1 = std::chrono::high_resolution_clock::now();
  float kernel_time_mad_dp =
      std::chrono::duration<float, std::milli>(t1 - t0).count();

  float kernel_time_mad_hp = 0.f;
  if (doHalfs) {
    t0 = std::chrono::high_resolution_clock::now();
    benchmark_func_cpu<half2, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE,
                       compute_iterations, false>(
        conv_int<half2>(1), reinterpret_cast<half2*>(cd), TOTAL_BLOCKS);
    t1 = std::chrono::high_resolution_clock::now();
    kernel_time_mad_hp =
        std::chrono::duration<float, std::milli>(t1 - t0).count();
  }

  t0 = std::chrono::high_resolution_clock::now();
  benchmark_func_cpu<int, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE,
                     compute_iterations, true>(1, reinterpret_cast<int*>(cd),
                                               TOTAL_BLOCKS);
  t1 = std::chrono::high_resolution_clock::now();
  float kernel_time_mad_int =
      std::chrono::duration<float, std::milli>(t1 - t0).count();

  printf(
      "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
      "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
      compute_iterations,
      ((double)computations) / ((double)memoryoperations * sizeof(float)),
      kernel_time_mad_sp,
      ((double)computations) / kernel_time_mad_sp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(double)),
      kernel_time_mad_dp,
      ((double)computations) / kernel_time_mad_dp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)2 * computations) / ((double)memoryoperations * sizeof(half2)),
      kernel_time_mad_hp,
      ((double)2 * computations) / kernel_time_mad_hp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(half2)) / kernel_time_mad_hp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(int)),
      kernel_time_mad_int,
      ((double)computations) / kernel_time_mad_int * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
          (1000. * 1000. * 1000.));
}

